import { useState, useRef, useEffect } from "react";

// ─── THEME ────────────────────────────────────────────────────────────────────
const T = {
  bg: "#f0f4ff",
  bg1: "#ffffff",
  bg2: "#f7f9ff",
  bg3: "#eef1fb",
  border: "#e2e8ff",
  border2: "#c8d2f5",
  text: "#1a1f3a",
  text2: "#4a5080",
  text3: "#8890b8",
  purple: "#6c5ce7",
  purpleL: "#a29bfe",
  pink: "#fd79a8",
  green: "#00b894",
  amber: "#fdcb6e",
  red: "#e17055",
  blue: "#0984e3",
  teal: "#00cec9",
  coral: "#ff7675",
  shadow: "0 4px 24px rgba(108,92,231,0.10)",
  shadowHover: "0 8px 32px rgba(108,92,231,0.18)",
};

const SECTIONS = [
  { id: 1, title: "Beginner", emoji: "🌱", color: "#00b894", desc: "Start your journey here" },
  { id: 2, title: "Intermediate", emoji: "🚀", color: "#6c5ce7", desc: "Level up your skills" },
  { id: 3, title: "Advanced", emoji: "⚡", color: "#fd79a8", desc: "Master the subject" },
];

const INIT_MODULES = [
  { id: 1, sectionId: 1, title: "Module 1: Foundations", color: "#00b894", emoji: "🌿", desc: "Core concepts and theory", lessons: 8, progress: 78, status: "published" },
  { id: 2, sectionId: 1, title: "Module 2: Basics", color: "#fdcb6e", emoji: "⭐", desc: "Essential skills and practice", lessons: 6, progress: 45, status: "published" },
  { id: 3, sectionId: 2, title: "Module 3: Deep Dive", color: "#6c5ce7", emoji: "🔮", desc: "Advanced techniques", lessons: 7, progress: 20, status: "published" },
  { id: 4, sectionId: 2, title: "Module 4: Projects", color: "#0984e3", emoji: "🛠️", desc: "Hands-on project work", lessons: 5, progress: 0, status: "draft" },
  { id: 5, sectionId: 3, title: "Module 5: Mastery", color: "#fd79a8", emoji: "🏆", desc: "Final capstone & certification", lessons: 4, progress: 0, status: "draft" },
];

const INIT_LESSONS = {
  1: [
    { id: 1, type: "video", title: "Welcome & Overview", dur: "08:12", done: true, url: "" },
    { id: 2, type: "video", title: "Key Concepts", dur: "14:30", done: true, url: "" },
    { id: 3, type: "reading", title: "Chapter 1 Reading", pages: 18, done: true },
    { id: 4, type: "quiz", title: "Foundations Quiz", questions: [], done: true, score: 92 },
    { id: 5, type: "video", title: "Deep Dive Theory", dur: "22:05", done: false, url: "" },
    { id: 6, type: "assignment", title: "Assignment 1", deadline: "June 20", done: false },
  ],
  2: [
    { id: 1, type: "video", title: "Basics Intro", dur: "10:00", done: true, url: "" },
    { id: 2, type: "quiz", title: "Quick Check", questions: [], done: false },
    { id: 3, type: "assignment", title: "Practice Task", deadline: "June 25", done: false },
  ],
};

const STUDENTS = [
  { id: 1, name: "Aisha N.", av: "AN", col: "#6c5ce7", prog: 78, grade: "A", active: "2h ago" },
  { id: 2, name: "Damir S.", av: "DS", col: "#00b894", prog: 62, grade: "B+", active: "1h ago" },
  { id: 3, name: "Zarina B.", av: "ZB", col: "#fd79a8", prog: 91, grade: "A+", active: "5m ago" },
  { id: 4, name: "Ruslan A.", av: "RA", col: "#0984e3", prog: 44, grade: "C+", active: "3d ago" },
  { id: 5, name: "Madina O.", av: "MO", col: "#fdcb6e", prog: 28, grade: "D", active: "1w ago" },
];

let CHAT_MSGS = [
  { id: 1, author: "Instructor", av: "IN", col: T.purple, msg: "Welcome everyone! 🎉 Ask anything here anytime!", self: false, time: "09:00" },
  { id: 2, author: "Zarina B.", av: "ZB", col: T.pink, msg: "Thank you! Really enjoying the course 😊", self: false, time: "09:12" },
  { id: 3, author: "You", av: "YO", col: T.blue, msg: "Module 4 unlocks next week!", self: true, time: "10:00" },
];

// ─── HELPERS ─────────────────────────────────────────────────────────────────
function Av({ name, color, size = 34 }) {
  const ini = (name || "?").split(" ").map(w => w[0]).join("").slice(0, 2).toUpperCase();
  return (
    <div style={{ width: size, height: size, borderRadius: "50%", background: color + "22", border: `2px solid ${color}55`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: size * 0.32, fontWeight: 800, color, flexShrink: 0, fontFamily: "'Nunito', sans-serif" }}>
      {ini}
    </div>
  );
}

function Bar({ val, color, h = 6 }) {
  return (
    <div style={{ height: h, background: T.bg3, borderRadius: 99, overflow: "hidden" }}>
      <div style={{ height: "100%", width: `${Math.min(100, val || 0)}%`, background: `linear-gradient(90deg, ${color}, ${color}bb)`, borderRadius: 99, transition: "width 0.6s cubic-bezier(.4,0,.2,1)" }} />
    </div>
  );
}

function Chip({ label, color, small }) {
  return (
    <span style={{ background: color + "18", color, border: `1.5px solid ${color}33`, borderRadius: 20, padding: small ? "2px 8px" : "4px 12px", fontSize: small ? 10 : 12, fontWeight: 700, display: "inline-flex", alignItems: "center", gap: 3 }}>
      {label}
    </span>
  );
}

function Card({ children, style, onClick, hover }) {
  const [hov, setHov] = useState(false);
  return (
    <div onClick={onClick} onMouseEnter={() => setHov(true)} onMouseLeave={() => setHov(false)}
      style={{ background: T.bg1, border: `1.5px solid ${hov && hover ? T.border2 : T.border}`, borderRadius: 18, padding: "20px 22px", boxShadow: hov && hover ? T.shadowHover : T.shadow, transition: "all 0.2s", cursor: onClick ? "pointer" : "default", transform: hov && hover ? "translateY(-2px)" : "none", ...style }}>
      {children}
    </div>
  );
}

function Input({ label, value, onChange, placeholder, type = "text" }) {
  return (
    <div style={{ marginBottom: 14 }}>
      {label && <div style={{ color: T.text2, fontSize: 13, fontWeight: 600, marginBottom: 5 }}>{label}</div>}
      <input type={type} value={value} onChange={e => onChange(e.target.value)} placeholder={placeholder}
        style={{ width: "100%", background: T.bg2, border: `1.5px solid ${T.border}`, borderRadius: 10, padding: "10px 14px", color: T.text, fontSize: 14, outline: "none", fontFamily: "'Nunito', sans-serif", boxSizing: "border-box" }} />
    </div>
  );
}

function Btn({ children, onClick, color = T.purple, outline, small, disabled }) {
  const [hov, setHov] = useState(false);
  return (
    <button onClick={onClick} disabled={disabled} onMouseEnter={() => setHov(true)} onMouseLeave={() => setHov(false)}
      style={{ background: outline ? "transparent" : hov ? color + "dd" : color, border: `2px solid ${color}`, borderRadius: small ? 8 : 12, padding: small ? "5px 12px" : "10px 20px", color: outline ? color : "#fff", fontWeight: 700, fontSize: small ? 12 : 14, cursor: disabled ? "not-allowed" : "pointer", opacity: disabled ? 0.5 : 1, transition: "all 0.15s", fontFamily: "'Nunito', sans-serif", display: "inline-flex", alignItems: "center", gap: 6 }}>
      {children}
    </button>
  );
}

function Modal({ children, onClose, title }) {
  return (
    <div style={{ position: "fixed", inset: 0, background: "#1a1f3a55", zIndex: 300, display: "flex", alignItems: "center", justifyContent: "center", backdropFilter: "blur(4px)", padding: 20 }} onClick={e => e.target === e.currentTarget && onClose()}>
      <div style={{ background: T.bg1, borderRadius: 24, width: "min(580px, 95vw)", maxHeight: "85vh", overflow: "hidden", display: "flex", flexDirection: "column", boxShadow: "0 24px 80px rgba(108,92,231,0.2)" }}>
        {title && (
          <div style={{ padding: "20px 24px", borderBottom: `1.5px solid ${T.border}`, display: "flex", justifyContent: "space-between", alignItems: "center" }}>
            <div style={{ fontWeight: 800, fontSize: 17, color: T.text }}>{title}</div>
            <button onClick={onClose} style={{ background: T.bg3, border: "none", borderRadius: "50%", width: 32, height: 32, cursor: "pointer", fontSize: 16, color: T.text3 }}>✕</button>
          </div>
        )}
        <div style={{ padding: 24, overflowY: "auto" }}>{children}</div>
      </div>
    </div>
  );
}

// ─── VIDEO PLAYER ─────────────────────────────────────────────────────────────
function VideoModal({ lesson, onClose }) {
  const [playing, setPlaying] = useState(false);
  const [prog, setProg] = useState(0);
  const iv = useRef(null);
  const toggle = () => {
    if (playing) { clearInterval(iv.current); setPlaying(false); }
    else { setPlaying(true); iv.current = setInterval(() => setProg(p => { if (p >= 100) { clearInterval(iv.current); setPlaying(false); return 100; } return p + 0.4; }), 300); }
  };
  useEffect(() => () => clearInterval(iv.current), []);
  return (
    <Modal onClose={onClose} title={lesson.title}>
      <div style={{ background: "linear-gradient(135deg, #1a1f3a, #2d3561)", borderRadius: 14, aspectRatio: "16/9", display: "flex", alignItems: "center", justifyContent: "center", flexDirection: "column", gap: 12, marginBottom: 16 }}>
        <div style={{ fontSize: 52, filter: "drop-shadow(0 4px 12px rgba(108,92,231,0.4))" }}>🎬</div>
        <div style={{ color: "#ffffff88", fontSize: 13 }}>{lesson.title}</div>
      </div>
      <div style={{ height: 6, background: T.bg3, borderRadius: 99, cursor: "pointer", marginBottom: 14 }} onClick={e => { const r = e.currentTarget.getBoundingClientRect(); setProg(((e.clientX - r.left) / r.width) * 100); }}>
        <div style={{ height: "100%", width: `${prog}%`, background: `linear-gradient(90deg, ${T.purple}, ${T.pink})`, borderRadius: 99, transition: "width 0.1s" }} />
      </div>
      <div style={{ display: "flex", gap: 12, alignItems: "center" }}>
        <button onClick={toggle} style={{ background: `linear-gradient(135deg, ${T.purple}, ${T.pink})`, border: "none", borderRadius: "50%", width: 42, height: 42, color: "#fff", fontSize: 14, cursor: "pointer", boxShadow: "0 4px 12px rgba(108,92,231,0.3)" }}>
          {playing ? "⏸" : "▶"}
        </button>
        <span style={{ color: T.text2, fontSize: 13 }}>{lesson.dur || "00:00"}</span>
        <button onClick={onClose} style={{ marginLeft: "auto", background: T.bg3, border: `1.5px solid ${T.border}`, borderRadius: 10, color: T.text2, padding: "7px 16px", cursor: "pointer", fontFamily: "'Nunito', sans-serif", fontWeight: 600 }}>Close</button>
      </div>
    </Modal>
  );
}

// ─── QUIZ ─────────────────────────────────────────────────────────────────────
function QuizModal({ lesson, onClose }) {
  const qs = lesson.questions || [];
  const [cur, setCur] = useState(0);
  const [answers, setAnswers] = useState({});
  const [done, setDone] = useState(false);
  if (qs.length === 0) return <Modal onClose={onClose} title="Quiz"><div style={{ textAlign: "center", padding: 20, color: T.text3 }}>No questions added yet. Add them in the instructor panel!</div></Modal>;
  const q = qs[cur];
  const score = Math.round(Object.entries(answers).filter(([i, a]) => qs[i]?.correct === +a).length / qs.length * 100);
  const pick = (i) => {
    if (answers[cur] !== undefined) return;
    setAnswers(a => ({ ...a, [cur]: i }));
    setTimeout(() => { if (cur < qs.length - 1) setCur(c => c + 1); else setDone(true); }, 700);
  };
  return (
    <Modal onClose={onClose} title={lesson.title}>
      {done ? (
        <div style={{ textAlign: "center", padding: "20px 0" }}>
          <div style={{ fontSize: 60, marginBottom: 12 }}>{score >= 70 ? "🎉" : "📚"}</div>
          <div style={{ fontSize: 36, fontWeight: 800, color: score >= 70 ? T.green : T.amber, marginBottom: 8 }}>{score}%</div>
          <div style={{ color: T.text2, marginBottom: 24 }}>{score >= 70 ? "Excellent! You passed!" : "Keep studying and try again!"}</div>
          <Btn onClick={onClose}>Done</Btn>
        </div>
      ) : (
        <>
          <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 14 }}>
            <Chip label={`Q ${cur + 1} of ${qs.length}`} color={T.purple} />
          </div>
          <Bar val={(cur / qs.length) * 100} color={T.purple} h={8} />
          <div style={{ color: T.text, fontSize: 17, fontWeight: 700, margin: "18px 0 14px", lineHeight: 1.5 }}>{q.question}</div>
          {(q.options || []).map((opt, i) => {
            const sel = answers[cur] === i;
            const correct = answers[cur] !== undefined && i === q.correct;
            const wrong = sel && i !== q.correct;
            return (
              <button key={i} onClick={() => pick(i)} style={{ width: "100%", background: correct ? T.green + "18" : wrong ? T.red + "18" : sel ? T.purple + "18" : T.bg2, border: `2px solid ${correct ? T.green : wrong ? T.red : sel ? T.purple : T.border}`, borderRadius: 12, padding: "12px 16px", color: correct ? T.green : wrong ? T.red : sel ? T.purple : T.text2, textAlign: "left", cursor: "pointer", fontSize: 14, fontWeight: 600, marginBottom: 8, fontFamily: "'Nunito', sans-serif", transition: "all 0.2s" }}>
                <span style={{ opacity: 0.5, marginRight: 8 }}>{String.fromCharCode(65 + i)}.</span>{opt}
              </button>
            );
          })}
        </>
      )}
    </Modal>
  );
}

// ─── UPLOAD ───────────────────────────────────────────────────────────────────
function UploadModal({ lesson, onClose }) {
  const [files, setFiles] = useState([]);
  const [drag, setDrag] = useState(false);
  const [done, setDone] = useState(false);
  const ref = useRef();
  const addF = (fs) => setFiles(p => [...p, ...[...fs].map(f => ({ name: f.name, size: (f.size / 1024).toFixed(0) + " KB" }))]);
  return (
    <Modal onClose={onClose} title={lesson.title}>
      {done ? (
        <div style={{ textAlign: "center", padding: 20 }}>
          <div style={{ fontSize: 52, marginBottom: 12 }}>✅</div>
          <div style={{ color: T.green, fontWeight: 700, fontSize: 16, marginBottom: 20 }}>Submitted successfully!</div>
          <Btn onClick={onClose}>Close</Btn>
        </div>
      ) : (
        <>
          {lesson.deadline && <div style={{ color: T.amber, fontSize: 13, fontWeight: 600, marginBottom: 14 }}>⏰ Due: {lesson.deadline}</div>}
          <div onDragOver={e => { e.preventDefault(); setDrag(true); }} onDragLeave={() => setDrag(false)}
            onDrop={e => { e.preventDefault(); setDrag(false); addF(e.dataTransfer.files); }}
            onClick={() => ref.current.click()}
            style={{ border: `2px dashed ${drag ? T.purple : T.border2}`, borderRadius: 16, padding: "32px 20px", textAlign: "center", cursor: "pointer", background: drag ? T.purple + "08" : T.bg2, transition: "all 0.2s", marginBottom: 14 }}>
            <div style={{ fontSize: 32, marginBottom: 8 }}>📎</div>
            <div style={{ color: T.text2, fontSize: 14 }}>Drop files or <span style={{ color: T.purple, fontWeight: 700 }}>browse</span></div>
            <div style={{ color: T.text3, fontSize: 12, marginTop: 4 }}>PDF, DOCX, ZIP — max 50MB</div>
            <input ref={ref} type="file" multiple style={{ display: "none" }} onChange={e => addF(e.target.files)} />
          </div>
          {files.map((f, i) => (
            <div key={i} style={{ display: "flex", justifyContent: "space-between", background: T.bg2, border: `1.5px solid ${T.border}`, borderRadius: 10, padding: "9px 14px", marginBottom: 6 }}>
              <span style={{ color: T.text2, fontSize: 13 }}>📄 {f.name}</span>
              <span style={{ color: T.text3, fontSize: 12 }}>{f.size}</span>
            </div>
          ))}
          {files.length > 0 && <Btn onClick={() => setDone(true)} color={T.green} style={{ width: "100%", marginTop: 8 }}>Submit {files.length} File{files.length > 1 ? "s" : ""} ↑</Btn>}
        </>
      )}
    </Modal>
  );
}

// ─── INSTRUCTOR PANEL ─────────────────────────────────────────────────────────
function InstructorPanel({ modules, setModules, lessons, setLessons }) {
  const [view, setView] = useState("modules"); // modules | addModule | addLesson | addQuiz
  const [selMod, setSelMod] = useState(null);
  const [form, setForm] = useState({});
  const [quizQs, setQuizQs] = useState([]);
  const [newQ, setNewQ] = useState({ question: "", options: ["", "", "", ""], correct: 0 });
  const set = (k, v) => setForm(f => ({ ...f, [k]: v }));

  const saveModule = () => {
    if (!form.title) return;
    const id = Date.now();
    setModules(m => [...m, { id, sectionId: +form.sectionId || 1, title: form.title, color: form.color || T.purple, emoji: form.emoji || "📚", desc: form.desc || "", lessons: 0, progress: 0, status: "draft" }]);
    setLessons(l => ({ ...l, [id]: [] }));
    setForm({});
    setView("modules");
  };

  const saveLesson = () => {
    if (!form.title || !selMod) return;
    const lesson = { id: Date.now(), type: form.type || "video", title: form.title, dur: form.dur, pages: form.pages, deadline: form.deadline, url: form.url || "", done: false, questions: form.type === "quiz" ? quizQs : [] };
    setLessons(l => ({ ...l, [selMod]: [...(l[selMod] || []), lesson] }));
    setModules(m => m.map(mod => mod.id === selMod ? { ...mod, lessons: (mod.lessons || 0) + 1 } : mod));
    setForm({}); setQuizQs([]); setView("lessons");
  };

  const addQuizQ = () => {
    if (!newQ.question || newQ.options.some(o => !o)) return;
    setQuizQs(q => [...q, { ...newQ, correct: +newQ.correct }]);
    setNewQ({ question: "", options: ["", "", "", ""], correct: 0 });
  };

  const COLORS = ["#6c5ce7", "#00b894", "#fd79a8", "#0984e3", "#fdcb6e", "#e17055", "#00cec9"];
  const EMOJIS = ["📚", "🎯", "🚀", "⭐", "🔮", "🌿", "🏆", "🛠️", "💡", "🎓"];

  if (view === "addModule") return (
    <div style={{ animation: "fadeUp .25s ease" }}>
      <button onClick={() => setView("modules")} style={{ background: "none", border: "none", color: T.purple, cursor: "pointer", fontSize: 13, fontWeight: 700, marginBottom: 20, padding: 0, fontFamily: "'Nunito', sans-serif" }}>← Back</button>
      <Card>
        <div style={{ fontWeight: 800, fontSize: 17, color: T.text, marginBottom: 20 }}>✨ New Module</div>
        <Input label="Module Title" value={form.title || ""} onChange={v => set("title", v)} placeholder="e.g. Module 1: Foundations" />
        <Input label="Description" value={form.desc || ""} onChange={v => set("desc", v)} placeholder="Brief description..." />
        <div style={{ marginBottom: 14 }}>
          <div style={{ color: T.text2, fontSize: 13, fontWeight: 600, marginBottom: 8 }}>Section</div>
          <div style={{ display: "flex", gap: 8 }}>
            {SECTIONS.map(s => (
              <button key={s.id} onClick={() => set("sectionId", s.id)} style={{ flex: 1, padding: "10px 8px", borderRadius: 12, border: `2px solid ${form.sectionId === s.id ? s.color : T.border}`, background: form.sectionId === s.id ? s.color + "18" : T.bg2, cursor: "pointer", fontFamily: "'Nunito', sans-serif", fontSize: 12, fontWeight: 700, color: form.sectionId === s.id ? s.color : T.text3 }}>
                {s.emoji} {s.title}
              </button>
            ))}
          </div>
        </div>
        <div style={{ marginBottom: 14 }}>
          <div style={{ color: T.text2, fontSize: 13, fontWeight: 600, marginBottom: 8 }}>Color</div>
          <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
            {COLORS.map(c => (
              <button key={c} onClick={() => set("color", c)} style={{ width: 32, height: 32, borderRadius: "50%", background: c, border: form.color === c ? `3px solid ${T.text}` : "3px solid transparent", cursor: "pointer", transition: "all .15s" }} />
            ))}
          </div>
        </div>
        <div style={{ marginBottom: 20 }}>
          <div style={{ color: T.text2, fontSize: 13, fontWeight: 600, marginBottom: 8 }}>Icon</div>
          <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
            {EMOJIS.map(e => (
              <button key={e} onClick={() => set("emoji", e)} style={{ width: 38, height: 38, borderRadius: 10, border: `2px solid ${form.emoji === e ? T.purple : T.border}`, background: form.emoji === e ? T.purple + "18" : T.bg2, cursor: "pointer", fontSize: 18 }}>{e}</button>
            ))}
          </div>
        </div>
        <Btn onClick={saveModule} color={T.green}>✓ Create Module</Btn>
      </Card>
    </div>
  );

  if (view === "lessons" && selMod != null) {
    const mod = modules.find(m => m.id === selMod);
    const modLessons = lessons[selMod] || [];
    return (
      <div style={{ animation: "fadeUp .25s ease" }}>
        <button onClick={() => { setView("modules"); setSelMod(null); }} style={{ background: "none", border: "none", color: T.purple, cursor: "pointer", fontSize: 13, fontWeight: 700, marginBottom: 20, padding: 0, fontFamily: "'Nunito', sans-serif" }}>← All Modules</button>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
          <div>
            <div style={{ fontWeight: 800, fontSize: 18, color: T.text }}>{mod?.emoji} {mod?.title}</div>
            <div style={{ color: T.text3, fontSize: 13 }}>{modLessons.length} lessons</div>
          </div>
          <Btn onClick={() => setView("addLesson")} color={mod?.color || T.purple}>+ Add Lesson</Btn>
        </div>
        {modLessons.length === 0 ? (
          <Card style={{ textAlign: "center", padding: 40 }}>
            <div style={{ fontSize: 40, marginBottom: 12 }}>📭</div>
            <div style={{ color: T.text3, fontSize: 14 }}>No lessons yet. Add your first one!</div>
          </Card>
        ) : modLessons.map((l, i) => (
          <Card key={l.id} style={{ marginBottom: 10, display: "flex", gap: 14, alignItems: "center" }}>
            <div style={{ width: 36, height: 36, borderRadius: 10, background: mod?.color + "22", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 16, flexShrink: 0 }}>
              {l.type === "video" ? "▶" : l.type === "quiz" ? "✦" : l.type === "assignment" ? "↑" : "◎"}
            </div>
            <div style={{ flex: 1 }}>
              <div style={{ fontWeight: 700, fontSize: 14, color: T.text, marginBottom: 3 }}>{l.title}</div>
              <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
                <Chip label={l.type} color={mod?.color || T.purple} small />
                {l.dur && <span style={{ color: T.text3, fontSize: 11 }}>⏱ {l.dur}</span>}
                {l.deadline && <span style={{ color: T.amber, fontSize: 11 }}>⏰ {l.deadline}</span>}
                {l.questions?.length > 0 && <span style={{ color: T.green, fontSize: 11 }}>✦ {l.questions.length} questions</span>}
              </div>
            </div>
            <button onClick={() => setLessons(ls => ({ ...ls, [selMod]: ls[selMod].filter((_, j) => j !== i) }))} style={{ background: T.red + "18", border: "none", borderRadius: 8, color: T.red, padding: "6px 10px", cursor: "pointer", fontSize: 13 }}>🗑</button>
          </Card>
        ))}
      </div>
    );
  }

  if (view === "addLesson") return (
    <div style={{ animation: "fadeUp .25s ease" }}>
      <button onClick={() => setView("lessons")} style={{ background: "none", border: "none", color: T.purple, cursor: "pointer", fontSize: 13, fontWeight: 700, marginBottom: 20, padding: 0, fontFamily: "'Nunito', sans-serif" }}>← Back</button>
      <Card>
        <div style={{ fontWeight: 800, fontSize: 17, color: T.text, marginBottom: 20 }}>📝 New Lesson</div>
        <div style={{ marginBottom: 14 }}>
          <div style={{ color: T.text2, fontSize: 13, fontWeight: 600, marginBottom: 8 }}>Lesson Type</div>
          <div style={{ display: "flex", gap: 8 }}>
            {["video", "quiz", "assignment", "reading"].map(t => (
              <button key={t} onClick={() => set("type", t)} style={{ flex: 1, padding: "10px 6px", borderRadius: 12, border: `2px solid ${form.type === t ? T.purple : T.border}`, background: form.type === t ? T.purple + "18" : T.bg2, cursor: "pointer", fontFamily: "'Nunito', sans-serif", fontSize: 11, fontWeight: 700, color: form.type === t ? T.purple : T.text3 }}>
                {t === "video" ? "▶ Video" : t === "quiz" ? "✦ Quiz" : t === "assignment" ? "↑ Task" : "◎ Reading"}
              </button>
            ))}
          </div>
        </div>
        <Input label="Lesson Title" value={form.title || ""} onChange={v => set("title", v)} placeholder="e.g. Introduction to the topic" />
        {form.type === "video" && <Input label="YouTube URL (optional)" value={form.url || ""} onChange={v => set("url", v)} placeholder="https://youtube.com/watch?v=..." />}
        {form.type === "video" && <Input label="Duration" value={form.dur || ""} onChange={v => set("dur", v)} placeholder="e.g. 12:30" />}
        {form.type === "reading" && <Input label="Number of pages" value={form.pages || ""} onChange={v => set("pages", v)} placeholder="e.g. 15" />}
        {form.type === "assignment" && <Input label="Deadline" value={form.deadline || ""} onChange={v => set("deadline", v)} placeholder="e.g. June 30" />}

        {form.type === "quiz" && (
          <div style={{ marginTop: 8 }}>
            <div style={{ fontWeight: 700, fontSize: 14, color: T.text, marginBottom: 12 }}>Quiz Questions ({quizQs.length} added)</div>
            {quizQs.map((q, i) => (
              <div key={i} style={{ background: T.green + "10", border: `1.5px solid ${T.green}33`, borderRadius: 10, padding: "10px 14px", marginBottom: 8, display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                <div>
                  <div style={{ fontSize: 13, fontWeight: 600, color: T.text }}>{q.question}</div>
                  <div style={{ fontSize: 11, color: T.green }}>✓ Answer: {q.options[q.correct]}</div>
                </div>
                <button onClick={() => setQuizQs(q => q.filter((_, j) => j !== i))} style={{ background: "none", border: "none", color: T.red, cursor: "pointer" }}>✕</button>
              </div>
            ))}
            <div style={{ background: T.bg2, border: `1.5px solid ${T.border}`, borderRadius: 12, padding: 14, marginBottom: 8 }}>
              <div style={{ fontSize: 13, fontWeight: 600, color: T.text2, marginBottom: 8 }}>+ Add Question</div>
              <input value={newQ.question} onChange={e => setNewQ(q => ({ ...q, question: e.target.value }))} placeholder="Question text..." style={{ width: "100%", background: T.bg1, border: `1.5px solid ${T.border}`, borderRadius: 8, padding: "8px 12px", color: T.text, fontSize: 13, marginBottom: 8, fontFamily: "'Nunito', sans-serif", boxSizing: "border-box", outline: "none" }} />
              {newQ.options.map((opt, i) => (
                <div key={i} style={{ display: "flex", gap: 8, marginBottom: 6, alignItems: "center" }}>
                  <input type="radio" name="correct" checked={newQ.correct === i} onChange={() => setNewQ(q => ({ ...q, correct: i }))} />
                  <input value={opt} onChange={e => setNewQ(q => ({ ...q, options: q.options.map((o, j) => j === i ? e.target.value : o) }))} placeholder={`Option ${String.fromCharCode(65 + i)}`} style={{ flex: 1, background: T.bg1, border: `1.5px solid ${newQ.correct === i ? T.green : T.border}`, borderRadius: 8, padding: "7px 10px", color: T.text, fontSize: 12, fontFamily: "'Nunito', sans-serif", outline: "none" }} />
                </div>
              ))}
              <Btn onClick={addQuizQ} color={T.teal} small>+ Add Question</Btn>
            </div>
          </div>
        )}
        <div style={{ marginTop: 16 }}>
          <Btn onClick={saveLesson} color={T.green}>✓ Save Lesson</Btn>
        </div>
      </Card>
    </div>
  );

  // Modules list
  return (
    <div style={{ animation: "fadeUp .25s ease" }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 20 }}>
        <div>
          <div style={{ fontWeight: 800, fontSize: 18, color: T.text }}>🎛️ Instructor Panel</div>
          <div style={{ color: T.text3, fontSize: 13 }}>Manage your course content</div>
        </div>
        <Btn onClick={() => setView("addModule")} color={T.purple}>+ New Module</Btn>
      </div>
      {SECTIONS.map(sec => {
        const secMods = modules.filter(m => m.sectionId === sec.id);
        return (
          <div key={sec.id} style={{ marginBottom: 24 }}>
            <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 12, padding: "10px 16px", background: sec.color + "12", border: `1.5px solid ${sec.color}33`, borderRadius: 14 }}>
              <span style={{ fontSize: 20 }}>{sec.emoji}</span>
              <div>
                <div style={{ fontWeight: 800, fontSize: 14, color: sec.color }}>{sec.title}</div>
                <div style={{ color: T.text3, fontSize: 12 }}>{sec.desc} · {secMods.length} modules</div>
              </div>
            </div>
            {secMods.length === 0 ? (
              <div style={{ color: T.text3, fontSize: 13, padding: "8px 16px" }}>No modules in this section yet.</div>
            ) : secMods.map(m => (
              <Card key={m.id} hover style={{ marginBottom: 10, display: "flex", gap: 14, alignItems: "center" }} onClick={() => { setSelMod(m.id); setView("lessons"); }}>
                <div style={{ width: 44, height: 44, borderRadius: 14, background: m.color + "22", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 22, flexShrink: 0 }}>{m.emoji}</div>
                <div style={{ flex: 1 }}>
                  <div style={{ fontWeight: 700, fontSize: 14, color: T.text, marginBottom: 3 }}>{m.title}</div>
                  <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
                    <Chip label={m.status} color={m.status === "published" ? T.green : T.amber} small />
                    <span style={{ color: T.text3, fontSize: 12 }}>{m.lessons} lessons</span>
                  </div>
                </div>
                <span style={{ color: T.text3, fontSize: 18 }}>›</span>
              </Card>
            ))}
          </div>
        );
      })}
    </div>
  );
}

// ─── STUDENT MODULES ─────────────────────────────────────────────────────────
function StudentModules({ modules, lessons }) {
  const [openMod, setOpenMod] = useState(null);
  const [activeLesson, setActiveLesson] = useState(null);
  const mod = modules.find(m => m.id === openMod);

  if (openMod && mod) {
    const modLessons = lessons[openMod] || [];
    return (
      <div style={{ animation: "fadeUp .25s ease" }}>
        {activeLesson?.type === "video" && <VideoModal lesson={activeLesson} onClose={() => setActiveLesson(null)} />}
        {activeLesson?.type === "quiz" && <QuizModal lesson={activeLesson} onClose={() => setActiveLesson(null)} />}
        {activeLesson?.type === "assignment" && <UploadModal lesson={activeLesson} onClose={() => setActiveLesson(null)} />}
        <button onClick={() => setOpenMod(null)} style={{ background: "none", border: "none", color: T.purple, cursor: "pointer", fontSize: 13, fontWeight: 700, marginBottom: 20, padding: 0, fontFamily: "'Nunito', sans-serif" }}>← All Modules</button>
        <Card style={{ marginBottom: 20, background: `linear-gradient(135deg, ${mod.color}18, ${T.bg1})`, border: `2px solid ${mod.color}33` }}>
          <div style={{ display: "flex", gap: 14, alignItems: "center", marginBottom: 14 }}>
            <div style={{ width: 52, height: 52, borderRadius: 16, background: mod.color + "22", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 26 }}>{mod.emoji}</div>
            <div style={{ flex: 1 }}>
              <div style={{ fontWeight: 800, fontSize: 18, color: T.text, marginBottom: 3 }}>{mod.title}</div>
              <div style={{ color: T.text2, fontSize: 13 }}>{mod.desc}</div>
            </div>
            <div style={{ textAlign: "center" }}>
              <div style={{ fontSize: 28, fontWeight: 800, color: mod.color }}>{mod.progress}%</div>
              <div style={{ color: T.text3, fontSize: 11 }}>complete</div>
            </div>
          </div>
          <Bar val={mod.progress} color={mod.color} h={8} />
        </Card>
        {modLessons.length === 0 ? (
          <Card style={{ textAlign: "center", padding: 40 }}>
            <div style={{ fontSize: 40, marginBottom: 12 }}>📭</div>
            <div style={{ color: T.text3, fontSize: 14 }}>No lessons added yet. Check back soon!</div>
          </Card>
        ) : modLessons.map((lesson, i) => (
          <Card key={lesson.id} hover style={{ marginBottom: 10, display: "flex", gap: 14, alignItems: "center", opacity: lesson.done ? 0.8 : 1 }}
            onClick={() => lesson.type !== "reading" && setActiveLesson(lesson)}>
            <div style={{ width: 32, height: 32, borderRadius: "50%", background: lesson.done ? T.green + "22" : T.bg3, border: `2px solid ${lesson.done ? T.green : T.border2}`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 12, color: lesson.done ? T.green : T.text3, fontWeight: 800, flexShrink: 0 }}>
              {lesson.done ? "✓" : i + 1}
            </div>
            <div style={{ flex: 1 }}>
              <div style={{ fontWeight: 700, fontSize: 14, color: T.text, marginBottom: 4 }}>{lesson.title}</div>
              <div style={{ display: "flex", gap: 7, flexWrap: "wrap", alignItems: "center" }}>
                <Chip label={lesson.type} color={mod.color} small />
                {lesson.dur && <span style={{ color: T.text3, fontSize: 11 }}>⏱ {lesson.dur}</span>}
                {lesson.deadline && <span style={{ color: T.amber, fontSize: 11 }}>⏰ {lesson.deadline}</span>}
                {lesson.score != null && <span style={{ color: T.green, fontSize: 11 }}>Score: {lesson.score}%</span>}
              </div>
            </div>
            {lesson.type !== "reading" && !lesson.done && <span style={{ color: T.text3, fontSize: 18 }}>›</span>}
          </Card>
        ))}
      </div>
    );
  }

  return (
    <div style={{ animation: "fadeUp .25s ease" }}>
      {SECTIONS.map(sec => {
        const secMods = modules.filter(m => m.sectionId === sec.id);
        if (secMods.length === 0) return null;
        return (
          <div key={sec.id} style={{ marginBottom: 28 }}>
            <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 14 }}>
              <div style={{ width: 36, height: 36, borderRadius: 12, background: sec.color + "18", border: `2px solid ${sec.color}33`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 18 }}>{sec.emoji}</div>
              <div>
                <div style={{ fontWeight: 800, fontSize: 15, color: sec.color }}>{sec.title}</div>
                <div style={{ color: T.text3, fontSize: 12 }}>{secMods.length} modules</div>
              </div>
            </div>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(240px,1fr))", gap: 12 }}>
              {secMods.map(m => (
                <Card key={m.id} hover onClick={() => setOpenMod(m.id)} style={{ background: `linear-gradient(135deg, ${m.color}10, ${T.bg1})`, border: `2px solid ${m.color}22` }}>
                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 12 }}>
                    <div style={{ width: 44, height: 44, borderRadius: 14, background: m.color + "22", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 22 }}>{m.emoji}</div>
                    <Chip label={m.progress + "%"} color={m.color} />
                  </div>
                  <div style={{ fontWeight: 800, fontSize: 14, color: T.text, marginBottom: 4 }}>{m.title}</div>
                  <div style={{ color: T.text2, fontSize: 12, marginBottom: 12 }}>{m.desc}</div>
                  <Bar val={m.progress} color={m.color} h={6} />
                  <div style={{ color: T.text3, fontSize: 11, marginTop: 8 }}>{m.lessons} lessons</div>
                </Card>
              ))}
            </div>
          </div>
        );
      })}
    </div>
  );
}

// ─── CHAT ─────────────────────────────────────────────────────────────────────
function ChatTab() {
  const [msgs, setMsgs] = useState(CHAT_MSGS);
  const [input, setInput] = useState("");
  const ref = useRef();
  useEffect(() => ref.current?.scrollIntoView({ behavior: "smooth" }), [msgs]);
  const send = () => {
    if (!input.trim()) return;
    const m = { id: Date.now(), author: "You", av: "YO", col: T.blue, msg: input, self: true, time: new Date().toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" }) };
    setMsgs(ms => [...ms, m]);
    CHAT_MSGS = [...CHAT_MSGS, m];
    setInput("");
  };
  return (
    <div style={{ display: "flex", flexDirection: "column", height: "calc(100vh - 130px)" }}>
      <div style={{ display: "flex", alignItems: "center", gap: 8, padding: "0 0 14px", borderBottom: `2px solid ${T.border}`, marginBottom: 14 }}>
        <div style={{ width: 10, height: 10, borderRadius: "50%", background: T.green, boxShadow: `0 0 8px ${T.green}` }} />
        <span style={{ color: T.text2, fontSize: 13, fontWeight: 600 }}>Group Chat · 50 members online</span>
      </div>
      <div style={{ flex: 1, overflowY: "auto", display: "flex", flexDirection: "column", gap: 12 }}>
        {msgs.map(m => (
          <div key={m.id} style={{ display: "flex", gap: 10, flexDirection: m.self ? "row-reverse" : "row" }}>
            <Av name={m.av} color={m.col} size={32} />
            <div style={{ maxWidth: "72%" }}>
              {!m.self && <div style={{ color: T.text3, fontSize: 11, fontWeight: 600, marginBottom: 3 }}>{m.author}</div>}
              <div style={{ background: m.self ? `linear-gradient(135deg, ${T.purple}, ${T.blue})` : T.bg2, color: m.self ? "#fff" : T.text, border: m.self ? "none" : `1.5px solid ${T.border}`, borderRadius: m.self ? "18px 4px 18px 18px" : "4px 18px 18px 18px", padding: "10px 14px", fontSize: 14, lineHeight: 1.55, boxShadow: m.self ? `0 4px 12px ${T.purple}33` : "none" }}>
                {m.msg}
              </div>
              <div style={{ color: T.text3, fontSize: 10, marginTop: 3, textAlign: m.self ? "right" : "left" }}>{m.time}</div>
            </div>
          </div>
        ))}
        <div ref={ref} />
      </div>
      <div style={{ display: "flex", gap: 10, paddingTop: 14, borderTop: `2px solid ${T.border}`, marginTop: 14 }}>
        <input value={input} onChange={e => setInput(e.target.value)} onKeyDown={e => e.key === "Enter" && send()} placeholder="Type a message..." style={{ flex: 1, background: T.bg2, border: `2px solid ${T.border}`, borderRadius: 14, padding: "11px 16px", color: T.text, fontSize: 14, outline: "none", fontFamily: "'Nunito', sans-serif" }} />
        <button onClick={send} style={{ background: `linear-gradient(135deg, ${T.purple}, ${T.blue})`, border: "none", borderRadius: 14, width: 44, height: 44, color: "#fff", cursor: "pointer", fontSize: 18, boxShadow: `0 4px 12px ${T.purple}33` }}>↑</button>
      </div>
    </div>
  );
}

