      <div style={{ background: `linear-gradient(135deg, ${T.purple}22, ${T.pink}11)`, border: `2px solid ${T.purple}22`, borderRadius: 22, padding: "28px 32px", marginBottom: 22, display: "flex", justifyContent: "space-between", alignItems: "center" }}>
        <div>
          <div style={{ color: T.purple, fontSize: 14, fontWeight: 700, marginBottom: 6 }}>Welcome back! 👋</div>
