      </div>

      <div style={{ display: "grid", gridTemplateColumns: "repeat(3,1fr)", gap: 14, marginBottom: 24 }}>
        {[
          { label: "Total Students", value: "50", color: T.purple, emoji: "👥" },
          { label: "Active Today", value: "18", color: T.green, emoji: "🟢" },
