      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill,minmax(220px,1fr))", gap: 12, marginBottom: 24 }}>
        {modules.map(m => (
          <Card key={m.id} hover style={{ background: `linear-gradient(135deg, ${m.color}10, ${T.bg1})`, border: `2px solid ${m.color}22` }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 10 }}>
              <span style={{ fontSize: 22 }}>{m.emoji}</span>
              <Chip label={m.progress + "%"} color={m.color} small />
            </div>
            <div style={{ fontWeight: 700, fontSize: 13, color: T.text, marginBottom: 8 }}>{m.title.split(":")[0]}</div>
            <Bar val={m.progress} color={m.color} h={6} />
          </Card>
        ))}
      </div>

      <div style={{ fontWeight: 800, fontSize: 16, color: T.text, marginBottom: 14 }}>📣 Announcements</div>
      {[
        { emoji: "📅", title: "Live Q&A this Friday at 18:00", body: "Covering Module 1 and 2. Join Zoom link in chat!", time: "1d ago" },
        { emoji: "🆕", title: "Module 3 resources updated", body: "New reading and bonus video added.", time: "3d ago" },
      ].map((a, i) => (
        <Card key={i} style={{ marginBottom: 10, display: "flex", gap: 14, alignItems: "flex-start" }}>
          <span style={{ fontSize: 24 }}>{a.emoji}</span>
          <div style={{ flex: 1 }}>
            <div style={{ fontWeight: 700, fontSize: 14, color: T.text, marginBottom: 3 }}>{a.title}</div>
            <div style={{ color: T.text2, fontSize: 13 }}>{a.body}</div>
