      <div style={{ color: T.text2, fontSize: 13, fontWeight: 600, marginBottom: 16 }}>👥 50 students enrolled</div>
      {STUDENTS.map(s => (
        <Card key={s.id} style={{ marginBottom: 10, display: "flex", gap: 14, alignItems: "center" }}>
